module RefModule(
    input clk,
    input rst,
    input din,
    output reg [7:0] dout
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt)
    if (rst)
        dout <= 8'b00000000;
    else
        dout <= {1'b0, dout[7:1]};

endmodule
